/**
 * tsgrid-ui/icons — SVG icon module (v3.0.0)
 *
 * 18 named icon functions, each returning an HTML SVG string.
 * Theming via fill="currentColor" — color is inherited from CSS.
 * Accessibility: aria-hidden="true" by default; role="img" + aria-label when label is provided.
 *
 * Design: D-1..D-10 from sdd/svg-component-icons/design (#1139)
 * Spec: R-SCI-1..5, R-A11y-1..6 from sdd/svg-component-icons/spec (#1138)
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/**
 * TsgIconName — union of all 18 icon kebab-case name strings (R-SCI-4)
 */
export type TsgIconName =
    | 'box'
    | 'check'
    | 'chevron-down'
    | 'collapse'
    | 'colors'
    | 'columns'
    | 'cross'
    | 'drop'
    | 'empty'
    | 'expand'
    | 'eye-dropper'
    | 'info'
    | 'paste'
    | 'pencil'
    | 'plus'
    | 'reload'
    | 'search'
    | 'settings'

/**
 * IconOpts — optional configuration for icon rendering (R-SCI-5)
 */
export interface IconOpts {
    /** Accessible label. When provided: role="img" + aria-label. When absent: aria-hidden="true". */
    label?: string
    /** CSS class appended to the <svg> element. No default class on <svg> (D-7). */
    class?: string
    /** Icon size in CSS pixels — sets width and height attributes (D-8). */
    size?: number
    /** Override fill color (e.g. 'red'). Default is 'currentColor' via CSS inheritance. */
    color?: string
}

// ---------------------------------------------------------------------------
// Private helpers
// ---------------------------------------------------------------------------

/**
 * _escapeAttr — HTML-attribute-escapes a string for safe embedding in SVG attribute values (R-A11y-3)
 */
function _escapeAttr(value: string): string {
    return value
        .replace(/&/g, '&amp;')
        .replace(/"/g, '&quot;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
}

/**
 * _renderSvg — builds the SVG string from inline path content and options (D-2, D-9)
 *
 * @param viewBox  — SVG viewBox attribute value
 * @param paths    — inner SVG content (path/polygon/etc. elements as a string)
 * @param opts     — optional IconOpts
 * @returns        — complete SVG HTML string
 */
function _renderSvg(viewBox: string, paths: string, opts?: IconOpts): string {
    const fill = opts?.color ? _escapeAttr(opts.color) : 'currentColor'
    let attrs = `xmlns="http://www.w3.org/2000/svg" viewBox="${viewBox}" fill="${fill}"`

    // Accessibility contract (R-A11y-1, R-A11y-2)
    if (opts?.label && opts.label.length > 0) {
        // label provided → role="img" + aria-label (no aria-hidden)
        attrs += ` role="img" aria-label="${_escapeAttr(opts.label)}"`
    } else {
        // no label → aria-hidden="true" (decorative)
        attrs += ' aria-hidden="true"'
    }

    // Optional class on <svg> element (D-7)
    if (opts?.class) {
        attrs += ` class="${_escapeAttr(opts.class)}"`
    }

    // Optional size (D-8): number = CSS pixels
    if (opts?.size !== undefined) {
        attrs += ` width="${opts.size}" height="${opts.size}"`
    }

    return `<svg ${attrs}>${paths}</svg>`
}

